var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"무슨 낯짝으로 내 앞에 나타나! 당장 썩 안 꺼져?!","JPN":"図々しくよくも会いにこれたものね！　今すぐ消えなさい！！","ENG":"How dare you show your face in front of me! Get out of my sight this instant!","TWN":"你有什麼臉出現在我面前！還不給我滾？！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"어쨌든 댁이 죽인 거잖아요. 지금 이 사정, 저 사정 다 이해해 달라고 협박하는 거예요?","JPN":"理由はどうあれ、あんたが殺したのには違いないじゃない。今あんたの事情を理解しろって脅すわけ？","ENG":"You're responsible for the death! Now you try to threaten us to \\"understand\\" your situation?!","TWN":"總之人是你殺的！你現在是威脅我要明白你的苦衷嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"가족을 잃은 사람들에겐 당신을 마주보는 것 자체가 힘든 일일 겁니다.","JPN":"家族を失った者にとっては、あなたと向かい合うこと自体が辛いことなんですよ。","ENG":"Imagine how painful it must be for them to look at you, when you're the one who killed one of their beloved.","TWN":"對失去家人的人而言，根本看都不想看你一眼。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"차라리…… 그냥 쥐 죽은 듯이 사세요.","JPN":"いっそ……誰ともかかわらずひっそり生きたらいいわ。","ENG":"Just... Never show your face around us ever again.","TWN":"我……還你寧願你什麼都不說，什麼都不做，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"그게 서로를 위해 나은 길 아닌가요?","JPN":"それがお互いのためじゃないですか？","ENG":"Won't that be best for all of us?","TWN":"這樣不是對彼此都好嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MASTER_EP9HALF_MANSION_VOICE","text":{"KOREA":"……그래. 추격할 필요까지는 없으니 이만 돌아오렴.","JPN":"……そう。追撃までは必要ないから、もう戻ってきなさい。","ENG":"...Very well. Stand back. There is no need to chase them.","TWN":"……好，不需要再追，回來吧。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_VOICE","text":{"KOREA":"왜, 놓쳤다던가?","JPN":"何だ、失敗したのか？","ENG":"Why? Did they lose them?","TWN":"怎麼？沒抓到人嗎？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MASTER_EP9HALF_MANSION_VOICE","text":{"KOREA":"내 꽃들이 그렇게 허술할 리가. 네 부탁대로 놓아 준 거란다.","JPN":"私の花たちがそんないい加減な仕事するわけないでしょう。あなたが頼んだとおり、行かせてあげたわ。","ENG":"My flowers are not that incompetent. I let them get away as you asked.","TWN":"我的花兒怎麼可能那麼沒用呢？已經照你吩咐的辦妥。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MASTER_EP9HALF_MANSION_VOICE","text":{"KOREA":"민병대라니, 나도 참 같잖은 것들과 다 엮여 보네.","JPN":"民兵隊だなんて、くだらないものに首を突っ込んだものね。","ENG":"\\"The Militia\\"... Who thought I would ever cross paths with them.","TWN":"民兵隊？我竟然也會和這種小角色扯上邊。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"흠. 일어났구나, 베로니카.","JPN":"ふうん。起きたわね、ベロニカ。","ENG":"Hmm... You're awake, Veronica.","TWN":"哼，你醒啦，貝洛妮卡？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래, 내 손을 떠나 있는 동안 달콤한 추억은 많이 쌓아 뒀니?","JPN":"どう、私の手から離れている間に甘い思い出はたくさん作れたかしら？","ENG":"So, tell me. Did you make many sweet memories after leaving my wing?","TWN":"怎麼樣？離開我後有累積許多美好的回憶嗎？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"마스터……?! 큭……!","JPN":"マスター……！？　くっ……！","ENG":"Master...?! Kgh...!","TWN":"主人……？！唔……！"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"사제 간의 감동적인 재회를 방해할 생각은 없지만, 지금은 안정을 취하길 바라지.","JPN":"師弟の感動的な再会を邪魔するつもりはないのだが、今は安静にした方がいい。","ENG":"I'd hate to interrupt such a touching reunion of master and pupil, but I need you to rest for now.","TWN":"我無意打擾你們主僕重逢的感人時刻，但現在還是先休養比較好吧。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"마담은 친우로서 나를 도와 준 거야. 해코지할 생각도, 이용할 생각도 없으니 안심하게.","JPN":"マダムは親友として私を手伝ってくれただけなんだ。害をなすつもりも、利用するつもりもないから安心したまえ。","ENG":"Madam is helping me as a friend. Rest assured. I have no intention of hurting you, or using you.","TWN":"夫人是我的好朋友，她只是好心幫忙我。我們沒有要害你，或是利用你的意思，放心吧。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"당신은…… 누구시죠?","JPN":"あなたは……どなたですか？","ENG":"Who... are you?","TWN":"你……是誰？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"보통은 시솝이라고들 부르지.","JPN":"通常はシソップと呼ばれている。","ENG":"People call me Sysop.","TWN":"大家都叫我錫索普。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"풋내기 주제에 귀찮은 참견쟁이란다. 그렇게 알고 있으렴.","JPN":"坊やのくせにいらぬお節介が大好きなの。知っておくといいわ。","ENG":"He's a nosy young fellow, and that's all you need to know.","TWN":"明明就是個小鬼，卻很愛多管閒事，我認識的他是這樣。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그렇게 말하니 섭섭하군, 마담. 나 같은 참견쟁이 아니면 누가 자네 연구를 도와 줬겠나.","JPN":"そう言われると悲しいな、マダム。私のようなお節介焼きでなければ誰が君の研究を手伝うんだい？","ENG":"Isn't that a bit harsh, madam? If it weren't for \\"nosy\\" me, then who would've helped you with your research?","TWN":"聽夫人這麼說，我有點難過呢。要不是我愛多管閒事，誰會幫忙你的研究呢？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"적당히 하렴. 과거를 들먹이는 건 그리 신사적이지 않아.","JPN":"いい加減にしなさい。過去を口にするのはあまり紳士的とは言えないわ。","ENG":"Easy now. It's not very gentlemanly to keep digging up a lady's past.","TWN":"適可而止就好，翻舊帳不是一個紳士該有的行為。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"하하, 작은 인연도 소중히 여긴다고 생각해 줘.","JPN":"はは、小さな縁も大事にしていると考えてくれ。","ENG":"Ha ha! Let's just say I cherish all my acquaintances.","TWN":"哈哈，夫人就當我念舊吧。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그럼 이야기를 다시 돌려서, 왜 죽으려고 했나?","JPN":"それでは元の話題に戻って、どうして死のうとしたのかね？","ENG":"Now, back to the subject at hand. Why did you try to get yourself killed?","TWN":"回到正題，你為什麼想尋死？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"무슨 말씀을 하시는 건지 모르겠군요.","JPN":"何のお話しでしょうか。","ENG":"I have no idea what you're talking about.","TWN":"我不明白你在說什麼。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"마담이 호언장담하더군. 아무리 녹슬었어도 자네가 그런 자들에게 당할 리 없다고 말이야.","JPN":"マダムが大言壮語していたんだ。いくら腕が衰えていたとしても、君があのような者たちにやられるわけがないとね。","ENG":"Madam was pretty adamant that even if you lost your touch, you would never get defeated by some punks.","TWN":"夫人信誓旦旦地說，就算你再怎麼退步，也不至於落到那種傢伙手裡。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그리고 내 생각에도 그래.","JPN":"私も同じ考えだ。","ENG":"And I believe she is right.","TWN":"我也同意夫人的說法。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"친우이기 이전에 마담의 실력은 놀라울 정도로 뛰어나지.","JPN":"親友である前に、マダムの実力は驚くほど優秀だ。","ENG":"Madam's abilities are astounding, and I do not say this just because we're friends.","TWN":"撇除夫人是我的好朋友不說，夫人本身的實力也不在話下。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"아무 쓸모 없어 보이는 약물들을 배합해 새로운 효능을 만드는 재주는 경이로울 정도야.","JPN":"一見何の役にも立ちそうにない薬物を配合し、新しい効能を作り出す腕前たるや目をみはるものがある。","ENG":"Her knack to create new effects by combining seemingly ineffective compounds is phenomenal.","TWN":"她可以將看似一點用處都沒有的藥物，調配出全新的效用，著實令人驚艷。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그 결실인 자네가 믿을 거라곤 독기뿐인 자들에게 쉽게 당할 리 없지.","JPN":"その結実である君が、頼れるものといえば毒気しかない者たちにそう簡単にやられるはずがない。","ENG":"And you, her poster child, cannot go down so easily by the spiteful.","TWN":"而身為成果的你，我相信當然不可能輕易輸給那種只有狠勁的傢伙。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"저들에게 제 죄를 단죄할 권리가 있다고 생각했을 뿐입니다.","JPN":"あの者たちに私の罪を断罪する権利があると思っただけです。","ENG":"I just assumed they had the right to condemn me of my crimes.","TWN":"我只是認為，他們有權利向我問罪。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"저들 손에 목숨을 잃으면, 얼굴도 모르는 피해자들에게 용서 받을 수 있다고 여긴 건가?","JPN":"彼らの手で命を落とせば、顔も知らない被害者に許されるとでも思ったのかい？","ENG":"Are you saying that you'll be forgiven by those faceless victims if you die in their hands?","TWN":"你以為只要死在他們手裡，那些連臉都認不出來的受害者就會原諒你嗎？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"정말 안타까운 발상이야.","JPN":"まったく残念な発想だ。","ENG":"What a pitiful idea.","TWN":"真是令人遺憾的想法。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"뭐가 안타깝다는 거죠?","JPN":"何が残念なのですか？","ENG":"What do you mean by that?","TWN":"哪裡遺憾？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"목숨으로 목숨을 계산한다는 건 비도덕적인 사고 방식이라고 하지만, 여기선 논외로 두지.","JPN":"命を命で計算するというのは非道徳的な考え方だというが、ここでは論外としておこう。","ENG":"Although they say paying back lives with another is immoral, I will leave that argument out for now.","TWN":"以人命來計算人命是不道德的思考方式，但我們現在先不談。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"설령 그들 손에 죽어 봤자 목숨 하나로 목숨 하나를 갚는 셈 아닌가?","JPN":"たとえ彼らの手にかかって死んだとしても、一つの命で返せるのは一つの命に過ぎないだろう？","ENG":"Even so, by dying in their hands, all you are doing is paying for one of the lives you have taken, no?","TWN":"若是死在他們手裡，就是一命償一命不是嗎？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"……무슨 말씀을 하고 싶으신 겁니까.","JPN":"……何をおっしゃりたいのですか。","ENG":"...What is it that you want to say to me?","TWN":"……你到底想說什麼？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"대를 택할지, 소를 택할지. 늦든 빠르든 세상은 사람을 선택의 기로에 세우게 돼 있어.","JPN":"大を取るか、それとも小を取るか。遅かれ早かれ世の中は人をして選択の岐路に立たせるだろう。","ENG":"Whether you choose high or low, or slow or fast. In the end, the world will always make you choose.","TWN":"無論是選擇大或小，快或慢，世界就是會一直把人放在選擇的十字路口。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"자, 그러니 묻지.","JPN":"さあ、それでは問う。","ENG":"So, let me ask you again.","TWN":"來，我問你。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"이제까지 죽인 사람들보다 더 많은 사람들을 구할 수 있다면.","JPN":"これまでに殺してきた人の数より、もっと多くの人を救うことができるのなら。","ENG":"If you could save more people than you have already killed...","TWN":"若你可以拯救的人數，比你殺過的人還多，"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그리고 그것으로 자네가 흘린 피를 씻으라고 한다면.","JPN":"そして、それで君が流してきた血の罪を償えと言ったら。","ENG":"And if you could wash away your sins by doing so...","TWN":"而且可以洗淨你手上沾染的血，"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"어떻게 하겠나?","JPN":"君はどうする？","ENG":"What would you do?","TWN":"那你會怎麼做？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"제 손에 다시 피를 묻혀서 말인가요?","JPN":"私の手をまた血で汚してですか？","ENG":"Are you asking me to taint my hands in blood again?","TWN":"意思是我的手要再沾血嗎？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"발상이 유연하지 못한 편이군. 방식은 그쪽 자유야.","JPN":"発想が柔軟ではないな。やり方はそちらの自由さ。","ENG":"I see you're not that creative. The method is up to you.","TWN":"你腦袋還轉不過來呢，方法是由你決定的。"},"stage":{"bg":"SS_MAID_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"하지만 어떤 방식을 택하든, 자네가 지금까지 쌓아 왔던 것들은 모두 잃게 되겠지.","JPN":"だがどんなやり方を選ぼうと、君が今まで積み重ねてきたものはすべて失うことになる。","ENG":"Whatever path you take, you will lose everything you have built thus far.","TWN":"不過，無論你選擇什麼方法，都會失去你至今累積的一切。"},"stage":{"bg":"SS_MAID_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그런 이야기라면 제 대답은 이미 정해져 있습니다.","JPN":"そういう話なら私の答えはすでに決まっています。","ENG":"If that's the case, then my answer is already decided.","TWN":"若是如此，那我已經有答案了。"},"stage":{"bg":"SS_MAID_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"당신들이 저에게 무슨 짓을 하더라도……","JPN":"あなたたちが私に何をしようとも……","ENG":"Whatever you try to do to me...","TWN":"無論你們要對我做什麼……"},"stage":{"bg":"SS_MAID_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"아. 이걸 말한다는 걸 깜빡 잊었군.","JPN":"あ。ひとつ言い忘れていた。","ENG":"Ah... I forgot to tell you this.","TWN":"忘記說一件事。"},"stage":{"bg":"SS_MAID_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그 <color=#ffd34c>구할 수 있는</color> 사람들 중에는, 자네 주인님도 예외가 아니야.","JPN":"その<color=#ffd34c>救うことができる</color>人々の中には、君のご主人様も含まれる。","ENG":"Among the people <color=#ffd34c>you can save</color>, your master is no exception.","TWN":"那些<color=#ffd34c>可以得救</color>的人之中，也包括你的主人。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};